from dataclasses import dataclass
from datetime import date
from enum import Enum

class ProgrammePhase(Enum):
    DISCOVERY    = "discovery"
    BUILD        = "build"
    INTEGRATION  = "integration"
    GO_LIVE      = "go_live"

@dataclass
class PhaseCommsOverride:
    phase: ProgrammePhase
    steering_frequency_days: int     # override for manage-closely cadence
    engineering_frequency_days: int
    executive_summary_frequency_days: int

PHASE_OVERRIDES: dict[ProgrammePhase, PhaseCommsOverride] = {
    ProgrammePhase.DISCOVERY: PhaseCommsOverride(
        ProgrammePhase.DISCOVERY, steering_frequency_days=14,
        engineering_frequency_days=7, executive_summary_frequency_days=30
    ),
    ProgrammePhase.BUILD: PhaseCommsOverride(
        ProgrammePhase.BUILD, steering_frequency_days=7,
        engineering_frequency_days=1, executive_summary_frequency_days=7
    ),
    ProgrammePhase.INTEGRATION: PhaseCommsOverride(
        ProgrammePhase.INTEGRATION, steering_frequency_days=3,
        engineering_frequency_days=1, executive_summary_frequency_days=7
    ),
    ProgrammePhase.GO_LIVE: PhaseCommsOverride(
        ProgrammePhase.GO_LIVE, steering_frequency_days=1,
        engineering_frequency_days=1, executive_summary_frequency_days=2
    ),
}

def current_phase(start_date: date, as_of: date) -> ProgrammePhase:
    weeks_elapsed = (as_of - start_date).days // 7
    if weeks_elapsed < 5:
        return ProgrammePhase.DISCOVERY
    if weeks_elapsed < 13:
        return ProgrammePhase.BUILD
    if weeks_elapsed < 17:
        return ProgrammePhase.INTEGRATION
    return ProgrammePhase.GO_LIVE
